	"dataSources": {
		"ds_0EcABXb2": {
			"name": "top_workflows_today",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json \"payload.isManual\"=false eventName=\"n8n.workflow.*\" \n| stats count(eval(eventName=\"n8n.workflow.started\")) AS Runs count(eval(eventName=\"n8n.workflow.failed\")) AS Errors by payload.workflowName \n| sort - Runs \n| rename payload.workflowName AS Workflow \n|  head 5",
				"queryParameters": {
					"earliest": "@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_4zR9S41Z": {
			"name": "workflow_start_rate",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json \"payload.isManual\"=false eventName=\"n8n.workflow.started\" \n| timechart count span=24h",
				"queryParameters": {
					"earliest": "-1d@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_6Ab0C8xW": {
			"name": "workflow_success_rate",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName=\"n8n.workflow.success\" \"payload.isManual\"=false \n| timechart count span=24h",
				"queryParameters": {
					"earliest": "-1d@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_6OySed1g": {
			"name": "workflow_failure_rate",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json \"payload.isManual\"=false eventName=\"n8n.workflow.failed\" \n| timechart count span=24h",
				"queryParameters": {
					"earliest": "-1d@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_EZsTVAIM": {
			"name": "change_activity",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.audit.package.*, n8n.audit.workflow.*) \n| rex mode=sed \"s/^n8n\\.audit\\.//g\" field=eventName \n| table _time, eventName, payload._email \n| rename eventName as Event, payload._email as Email, _time as Time \n| sort - Time \n| convert ctime(Time) timeformat=\"%Y-%m-%d %H:%M:%S\"",
				"queryParameters": {}
			},
			"type": "ds.search"
		},
		"ds_J2erwN7G": {
			"name": "workflow_duration",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (\"n8n.workflow.started\", \"n8n.workflow.success\", \"n8n.workflow.failed\") \"payload.isManual\"=false \n| stats max(_time) as end, min(_time) as start by payload.executionId \n| eval duration=end-start\n| stats avg(duration) as avg_duration \n| eval avg_duration = round(avg_duration,2)"
			},
			"type": "ds.search"
		},
		"ds_O5fdNOpb": {
			"name": "recent_security_activity",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.audit.user.login.failed, n8n.audit.user.signedup, n8n.audit.user.deleted,n8n.audit.user.api.created, n8n.audit.package.installed, n8n.audit.workflow.archived, n8n.audit.workflow.deleted, n8n.audit.user.credentials.*) \n| rex mode=sed \"s/^n8n\\.audit\\.//g\" field=eventName | eval email = coalesce('payload._email','payload.userEmail')\n| table _time, eventName, email\n| rename eventName as Event, email as Email, _time as Time \n| sort - Time \n| convert ctime(Time) timeformat=\"%Y-%m-%d %H:%M:%S\"",
				"queryParameters": {}
			},
			"type": "ds.search"
		},
		"ds_QXFRviZo": {
			"name": "top_workflows_today_timechart",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json \"payload.isManual\"=false eventName=\"n8n.workflow.started\" | timechart count by payload.workflowName limit=5 span=2h",
				"queryParameters": {
					"earliest": "@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_W0boPYRO": {
			"name": "queue_backlog_single_value",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.queue.job.enqueued, n8n.queue.job.dequeued) \n| stats count(eval(eventName=\"n8n.queue.job.enqueued\")) AS enqueued, count(eval(eventName=\"n8n.queue.job.dequeued\")) AS dequeued \n| fillnull enqueued, dequeued, value=0 \n| eval backlog=enqueued-dequeued",
				"queryParameters": {
					"earliest": "-60m@m",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_Xe3Tpbow": {
			"name": "llm_prompt_count",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName=\"n8n.ai.llm.generated\" \n|  timechart count span=24h",
				"queryParameters": {
					"earliest": "-48h@h",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_p0IpfwhA": {
			"name": "most_called_mcp_server",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json *sourcetypes* eventName=\"n8n.ai.tool.called\" | rename payload.msg as msg | spath input=msg path=tool.name | stats count by payload.nodeName, tool.name | sort - count | head 1 | eval server_and_tool = 'payload.nodeName'.\" - \".'tool.name' | table server_and_tool",
				"queryParameters": {
					"earliest": "-24h@h",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_r3ZLoiAd": {
			"name": "queue_activity",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName = n8n.queue.job.* \n|  rex field=eventName mode=sed \"s/^n8n\\.queue\\.job\\.//g\"\n|  timechart count by eventName",
				"queryParameters": {}
			},
			"type": "ds.search"
		},
		"ds_tBJsL4NE": {
			"name": "llm_token_usage",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName=\"*llm*\" message=\"n8n.ai.llm.generated\" \"payload.nodeType\"=\"@n8n/n8n-nodes-langchain.lmChatGoogleGemini\" \n| spath input=payload.msg path=response.tokenUsage.totalTokens \n| timechart sum(response.tokenUsage.totalTokens) span=24h",
				"queryParameters": {
					"earliest": "-48h@h",
					"latest": "now"
				}
			},
			"type": "ds.search"
		}
	},
